INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','HIGH','개인 조건 "매우 매우 가깝다"(FootballTransfers 단독) — 5년 계약 준비, 아스날 컨빈스 단계. 이적료 격차 큼: 빌라 £130m 요구 vs 아스날 €85m(반반 분할지급) 제안. [2026-07-09 watch: 개인조건 진전으로 등급 MEDIUM-HIGH→HIGH 상향, 단 이적료 협상은 미해결]','https://www.footballtransfers.com/en/transfer-news/uk-premier-league/2026/07/exclusive-arsenal-very-close-to-morgan-rogers-transfer-breakthrough ; https://www.teamtalk.com/arsenal/morgan-rogers-transfer-news-record-bid-imminent-from-arsenal-villa (2026-07-09)','HIGH — 아스날 개인조건 임박·완료 예상(로저스 아스날/바이에른만 희망); 이적료 이견(빌라 £130m+ vs 아스날 £85m). 재검증 2026-07-10.');
INSERT INTO transfer_outgoing VALUES(3,'2026-summer',1,'Juventus','HIGH','유벤투스와 개인조건 구두 합의(2029년까지 3년, 연봉 €5.5m — 현재 €7m에서 감액 수용). Fabrizio Romano: 유벤투스 다이렉트 컨택 확인. 이적료 격차: 빌라 최소 €10m 요구 vs 유벤투스 최대 €5m 추가 의향. [2026-07-09 watch: 개인조건 합의로 HIGH 유지·근거 보강, 협상은 월드컵 이후로 지연 전망]','https://www.goal.com/en/lists/emi-martinez-verbally-agrees-juventus-transfer-aston-villa-and-argentina-goalkeeper-prepared-to-reduce-salary/blt15e7adefed63d273 ; https://www.caughtoffside.com/2026/07/08/juventus-direct-contact-emiliano-martinez-fabrizio-romano/ (2026-07-09)','HIGH — 유벤투스와 구두합의(3년 2029), 급여 삭감 수용; 단 이적료 이견(빌라 €10m vs 유베 저가). 빌라는 레스테스 구두합의로 대체 준비. 재검증 2026-07-10.');
INSERT INTO transfer_outgoing VALUES(5,'2026-summer',16,'Fenerbahçe','MEDIUM-HIGH','왓킨스가 페네르바흐체 계약조건에 서명(구조 합의), 이적료만 남은 상태. 이적료 격차: 페네르바흐체 €25m 제안 vs 빌라 €35m 요구. 클럽간 협상은 월드컵 이후로 예정, 왓킨스는 2028년까지 계약 중.','https://www.astonvillanews.co.uk/transfers/why-aston-villa-are-set-for-ollie-watkins-heartbreak-as-fenerbahce-close-in ; https://uk.sports.yahoo.com/news/why-aston-villa-set-ollie-133854669.html (2026-07-09)','MEDIUM-HIGH — 페너바체와 개인조건(3년 €9m) 합의했으나 빌라 매각 거부(계약 2028)+이적료 이견(€35m vs €25m), 본인 WC 집중. 재검증 2026-07-10.');
INSERT INTO transfer_outgoing VALUES(6,'2026-summer',3,'Arsenal','MEDIUM','아스날이 벤 화이트 대체·살리바 백업으로 관심, 빌라는 £50-60m(~€70m) 요구하며 매각 의사 없음(계약 2년 남음). 로저스와 "더블 레이드" 패키지로도 거론.','https://www.footballinsider247.com/aston-villa/transfers/aston-villa-set-ezri-konsa-asking-price-as-arsenal-line-up-deal ; https://thehardtackle.com/transfer-news/2026/07/10/aston-villa-set-to-demand-over-50-million-for-ezri-konsa-amid-arsenal-links/ ; SofaScore/TransferFeed cross-check (2026-07-12)','MEDIUM — 2티어 복수(Football Insider, TheHardTackle, CaughtOffside) 관심·가격설정 보도가 수렴하나, 빌라는 매각 거부 입장이 명확하고 전문가들도 회의적("I don''t see Konsa leaving"). [2026-07-12 watch: 신규 추가]');
INSERT INTO transfer_outgoing VALUES(7,'2026-summer',9,'Manchester United','CONFIRMED','벨기에 월드컵 조별탈락 직후 맨유가 급가속. €41m(약 £35m) 바이아웃 조항 발동 임박 — Sky Sports "advanced talks", ESPN 소식통 확인. 본인 올드트래포드 선호 확인(ESPN). 빌라는 오나나 ACL 부상에 이어 두 번째 중원 손실 — 만잠비(LDM, 오늘 실측 추가)로 선제 대응했으나 만잠비는 공격형 성향이라 홀딩/DLP 자원 추가 필요. [갱신 07-14] Romano "HERE WE GO": €41m(£35m) 바이아웃 발동, 개인조건 합의, 메디컬 진행(부킹). [2026-07-14 야간 재확인] 메디컬 부킹(화요일) 보도(The Sun/Luckhurst), INEOS의 에더슨 영입 무산 후 신속 피벗 배경 확인 — CONFIRMED로 상향.','https://www.skysports.com/football/news/11095/13562972/youri-tielemans-manchester-united-in-talks-to-sign-aston-villa-and-belgium-midfielder ; https://www.espn.com/soccer/story/_/id/49348973/youri-tielemans-man-united-advanced-talks-aston-villa-sources ; https://www.footballtransfers.com/en/transfer-news/uk-premier-league/2026/07/man-utd-transfer-news-youri-tielemans-aston-villa-david-ornstein-advanced-talks-summer-2026 (2026-07-13) ; https://www.skysports.com (Plettenberg 메디컬 임박) ; Romano X/YouTube 07-14','CONFIRMED — Romano "here we go" + 메디컬 부킹 보도(복수 소스), 공식 발표만 남음.');
INSERT INTO transfer_outgoing VALUES(8,'2026-summer',5,'Paris Saint-Germain','CONFIRMED','PSG가 누누 멘데스 백업으로 재영입 타진, 이적료 규약상 바이아웃(약 €10m 추정)이 낮아 트리거 가능성. 6도움(PL 최다, 수비수 기준)으로 에메리 체계 핵심이나, 낮은 이적료가 매각 유인. PSG 슈퍼컵(8/12) 상대라는 아이러니. [갱신 07-14] Romano: PSG가 약 €10m 바이아웃 조항 발동, 디뉴 개인합의(누누 멘데스 백업 수용, 3년 계약). [2026-07-14 야간 재확인] 디뉴 본인 파리 복귀 수락 확인(누누 멘데스 백업), 월드컵 이후 바이아웃 발동 시점만 남음 — CONFIRMED로 상향.','https://readastonvilla.com/2026/07/13/aston-villa-face-major-digne-decision-after-psg-clause-emerges/ ; https://www.getfootballnewsfrance.com/2026/psg-express-interest-for-aston-villas-lucas-digne/ ; https://www.teamtalk.com/aston-villa/nightmare-scenario-psg-push-lucas-digne-youri-tielemans-exit (2026-07-13) ; https://www.getfootballnewsfrance.com/2026/psg-to-sign-aston-villas-lucas-digne-after-paying-e10m-release-clause/ (2026-07-14)','CONFIRMED — Romano "here we go"(1티어), 실행 시점만 월드컵 이후로 이연.');
